CREATE TABLE public.blocks (id integer NOT NULL, blocker_id integer NOT NULL, blocked_user_id integer NOT NULL, created_at timestamp with time zone DEFAULT now() NOT NULL);
CREATE SEQUENCE public.blocks_id_seq AS integer START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1;
ALTER SEQUENCE public.blocks_id_seq OWNED BY public.blocks.id;
CREATE TABLE public.districts (id integer NOT NULL, name text NOT NULL, county text NOT NULL, type text DEFAULT 'unified'::text NOT NULL, created_at timestamp with time zone DEFAULT now() NOT NULL);
CREATE SEQUENCE public.districts_id_seq AS integer START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1;
ALTER SEQUENCE public.districts_id_seq OWNED BY public.districts.id;
CREATE TABLE public.reports (id integer NOT NULL, reporter_id integer NOT NULL, reported_user_id integer NOT NULL, reason text NOT NULL, description text, created_at timestamp with time zone DEFAULT now() NOT NULL);
CREATE SEQUENCE public.reports_id_seq AS integer START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1;
ALTER SEQUENCE public.reports_id_seq OWNED BY public.reports.id;
CREATE TABLE public.request_tags (id integer NOT NULL, request_id integer NOT NULL, tag_id integer NOT NULL);
CREATE SEQUENCE public.request_tags_id_seq AS integer START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1;
ALTER SEQUENCE public.request_tags_id_seq OWNED BY public.request_tags.id;
CREATE TABLE public.requests (id integer NOT NULL, author_id integer NOT NULL, district_id integer NOT NULL, title text NOT NULL, description text NOT NULL, role text NOT NULL, status text DEFAULT 'open'::text NOT NULL, matched_user_id integer, created_at timestamp with time zone DEFAULT now() NOT NULL, updated_at timestamp with time zone DEFAULT now() NOT NULL);
CREATE SEQUENCE public.requests_id_seq AS integer START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1;
ALTER SEQUENCE public.requests_id_seq OWNED BY public.requests.id;
CREATE TABLE public.tags (id integer NOT NULL, name text NOT NULL, color text DEFAULT '#6366f1'::text NOT NULL, created_at timestamp with time zone DEFAULT now() NOT NULL);
CREATE SEQUENCE public.tags_id_seq AS integer START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1;
ALTER SEQUENCE public.tags_id_seq OWNED BY public.tags.id;
CREATE TABLE public.users (id integer NOT NULL, email text NOT NULL, name text NOT NULL, password_hash text NOT NULL, role text DEFAULT 'mentee'::text NOT NULL, district_id integer NOT NULL, bio text, subjects text[] DEFAULT '{}'::text[] NOT NULL, is_verified boolean DEFAULT true NOT NULL, created_at timestamp with time zone DEFAULT now() NOT NULL, updated_at timestamp with time zone DEFAULT now() NOT NULL);
CREATE SEQUENCE public.users_id_seq AS integer START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1;
ALTER SEQUENCE public.users_id_seq OWNED BY public.users.id;

ALTER TABLE ONLY public.blocks ALTER COLUMN id SET DEFAULT nextval('public.blocks_id_seq'::regclass);
ALTER TABLE ONLY public.districts ALTER COLUMN id SET DEFAULT nextval('public.districts_id_seq'::regclass);
